-- ============================================-- Supermarket Management System-- Database Creation Script-- Course: Visual Programming CS-412-- Run this in DB Browser for SQLite-- ============================================-- Users Table (Admin Login)CREATE TABLE IF NOT EXISTS users (id INTEGER PRIMARY KEY AUTOINCREMENT,username TEXT NOT NULL,password TEXT NOT NULL);-- Products TableCREATE TABLE IF NOT EXISTS products (id INTEGER PRIMARY KEY AUTOINCREMENT,product_name TEXT NOT NULL,category TEXT,price REAL NOT NULL,stock INTEGER DEFAULT 0);-- Customers TableCREATE TABLE IF NOT EXISTS customers (id INTEGER PRIMARY KEY AUTOINCREMENT,name TEXT NOT NULL,phone TEXT,email TEXT);-- Orders TableCREATE TABLE IF NOT EXISTS orders (id INTEGER PRIMARY KEY AUTOINCREMENT,customer_id INTEGER,order_date TEXT,total REAL,FOREIGN KEY (customer_id) REFERENCES customers(id));-- Order Items TableCREATE TABLE IF NOT EXISTS order_items (id INTEGER PRIMARY KEY AUTOINCREMENT,order_id INTEGER,product_id INTEGER,quantity INTEGER,price REAL,FOREIGN KEY (order_id) REFERENCES orders(id),FOREIGN KEY (product_id) REFERENCES products(id));-- Default Admin UserINSERT INTO users (username, password)VALUES ('admin', 'admin123');-- Sample Products DataINSERT INTO products (product_name, category, price, stock)VALUES('Rice 5kg', 'Grocery', 250.00, 100),('Milk 1L', 'Dairy', 60.00, 50),('Bread', 'Bakery', 35.00, 30),('Sugar 1kg', 'Grocery', 45.00, 80),('Tea 200g', 'Grocery', 120.00, 60);-- Sample Customers DataINSERT INTO customers (name, phone, email)VALUES('Ali Khan', '03001234567', 'ali@email.com'),('Sara Ahmed', '03009876543', 'sara@email.com');-- ============================================-- How to use this script:-- 1. Open DB Browser for SQLite-- 2. File → New Database → Supermarket.db-- 3. Execute SQL tab-- 4. Paste this script-- 5. Press F5 to run-- 6. Click Write Changes-- 7. Copy Supermarket.db to bin/Debug folder-- =======